--TABLAS
CREATE SEQUENCE  SEQ_MELANBIDE90_SUBSOLIC  MINVALUE 0 MAXVALUE 99999999 INCREMENT BY 1 START WITH 1 NOCACHE  NOORDER  NOCYCLE;

  CREATE TABLE MELANBIDE90_SUBSOLIC 
   (	ID NUMBER(8,0) NOT NULL ENABLE, 
	NUM_EXP VARCHAR2(30 BYTE), 
	ESTADO VARCHAR2(1 BYTE), 
	ORGANISMO VARCHAR2(150 BYTE), 
	OBJETO VARCHAR2(150 BYTE), 
    IMPORTE NUMBER(8,2), 
	FECHA DATE,  
	 CONSTRAINT MELANBIDE90_SUBSOLIC_PK PRIMARY KEY (ID)
 )
 ;

   COMMENT ON COLUMN MELANBIDE90_SUBSOLIC.ESTADO IS 'Estado de la Ayuda';
   COMMENT ON COLUMN MELANBIDE90_SUBSOLIC.ORGANISMO IS 'Organismo concedente';
   COMMENT ON COLUMN MELANBIDE90_SUBSOLIC.OBJETO IS 'Descripción objeto de la ayuda';
   COMMENT ON COLUMN MELANBIDE90_SUBSOLIC.FECHA IS 'Fecha Solicitud o Concesión';


